import { type PropsWithChildren, type UIEventHandler, useState } from 'react';
import { createPortal } from 'react-dom';

import { OverlayStackingProvider } from '../../../../../core/providers/OverlayStackingProvider.js';
import { useDynamicTooltip } from '../hooks/useDynamicTooltip.js';
import { TooltipContainerDimensionProvider } from '../providers/tooltip-container-dimensions.Provider.js';
import { wrapper } from '../tooltip.sty.js';

export type TooltipPortalProps = PropsWithChildren<{
  isInteractive: boolean;
  absoluteX: number;
  absoluteY: number;
  onMouseLeave?: () => void;
  onScrollCapture?: UIEventHandler<HTMLDivElement>;
}>;

export const TooltipPortal = (props: TooltipPortalProps) => {
  const { absoluteX, absoluteY, isInteractive, onMouseLeave, onScrollCapture } =
    props;
  const [tooltipWrapper, setTooltipWrapper] = useState<HTMLDivElement | null>(
    null,
  );
  const dynamicTooltip = useDynamicTooltip({
    template: tooltipWrapper,
    x: absoluteX,
    y: absoluteY,
  });

  return createPortal(
    <div
      role="tooltip"
      aria-label="OverlayTooltip"
      ref={setTooltipWrapper}
      className={wrapper({ isInteractive })}
      onMouseLeave={onMouseLeave}
      onScrollCapture={onScrollCapture}
      {...dynamicTooltip}
    >
      <OverlayStackingProvider>
        <TooltipContainerDimensionProvider container={tooltipWrapper}>
          {props.children}
        </TooltipContainerDimensionProvider>
      </OverlayStackingProvider>
    </div>,
    document.body,
  );
};
